package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases adds a handful of *edge* scenarios for
// Order.CalculateTotal().  The existing suite already checks the “happy‑path”
// cases (empty order, normal totals, large orders, float‑precision, etc.).  The
// sub‑tests below focus on values that can produce NaN, ±Inf or otherwise
// surprising results – situations that the business logic does **not** guard
// against (validation happens in Order.Validate, not in CalculateTotal).
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Parallel()

	type tc struct {
		name   string
		items  []OrderItem
		expect func(total float64) bool // predicate that validates the result
	}

	cases := []tc{
		{
			name: "NaNPrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
			},
			// Any operation with NaN yields NaN.
			expect: func(total float64) bool { return math.IsNaN(total) },
		},
		{
			name: "InfinityPrice",
			items: []OrderItem{
				{ProductID: 2, Quantity: 1, Price: math.Inf(1)},
			},
			expect: func(total float64) bool { return math.IsInf(total, 1) },
		},
		{
			name: "NegativePrice",
			items: []OrderItem{
				{ProductID: 3, Quantity: 2, Price: -10.0},
			},
			expect: func(total float64) bool { return total == -20.0 },
		},
		{
			name: "ZeroQuantity",
			items: []OrderItem{
				{ProductID: 4, Quantity: 0, Price: 123.45},
			},
			expect: func(total float64) bool { return total == 0.0 },
		},
		{
			name: "LargeValuesOverflow",
			items: []OrderItem{
				{ProductID: 5, Quantity: 2, Price: math.MaxFloat64},
			},
			// MaxFloat64 * 2 overflows to +Inf.
			expect: func(total float64) bool { return math.IsInf(total, 1) },
		},
		{
			name: "SmallValuesUnderflow",
			items: []OrderItem{
				{ProductID: 6, Quantity: 1, Price: math.SmallestNonzeroFloat64},
			},
			expect: func(total float64) bool {
				// The value should be exactly the smallest positive subnormal number.
				return total == math.SmallestNonzeroFloat64
			},
		},
		{
			name: "MixedNaNAndNormal",
			items: []OrderItem{
				{ProductID: 7, Quantity: 1, Price: 10.0},
				{ProductID: 8, Quantity: 1, Price: math.NaN()},
			},
			// NaN propagates through the sum.
			expect: func(total float64) bool { return math.IsNaN(total) },
		},
	}

	for _, c := range cases {
		c := c // capture range variable
		t.Run(c.name, func(t *testing.T) {
			t.Parallel()

			o := Order{
				Items: c.items,
			}
			o.CalculateTotal()

			if !c.expect(o.Total) {
				t.Fatalf("unexpected total for case %q: got %v", c.name, o.Total)
			}
		})
	}
}
```

### Why this test does **not** duplicate existing ones
| Existing test | What it covers | What this test adds |
|---------------|----------------|---------------------|
| `TestUnitOrderCalculateTotal` | Normal items, positive prices, normal quantities | Edge numeric values (NaN, ±Inf, negative price, zero quantity, overflow/underflow) |
| `TestUnitOrderCalculateTotalEmpty` | Empty slice → 0 | Zero‑quantity item (non‑empty slice but contribution 0) |
| `TestUnitOrderCalculateTotalSingleItem` | Single positive price | Negative price handling |
| `TestUnitOrderCalculateTotalLargeOrder` | Many items, normal totals | Very large price causing overflow to Inf |
| `TestUnitOrderCalculateTotalFloatPrecision` | 0.1/0.2 rounding tolerance | NaN/Inf propagation, sub‑normal values |
| `TestUnitOrderCalculateTotalSetsField` | Overwrites pre‑set Total | Same method, but we focus on the *value* produced, not the overwrite behaviour |

All sub‑tests are table‑driven, run in parallel, and use only the `entity` package – no repository or DB involvement, matching the style of the rest of the entity test suite.

