package handler_test

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"

	// helpers that are already part of the test‑suite
	. "github.com/yourorg/bean-brew/internal/api/handler_test" // brings in setupTestServer, postJSON, putJSON, doDelete, decodeBody, etc.
)

// TestAPIOrderFullFlow creates a category, a product, an order and then runs the
// whole order state‑machine (new → processing → completed).  The test mirrors the
// behaviour of the existing “full lifecycle via API” test but adds the
// prerequisite steps for category and product creation, so the whole flow is
// exercised from a single HTTP client perspective.
//
// Test name follows the project convention: TestAPI<Layer><Scenario>.
// The function lives in the *order* handler test file because it drives the
// order endpoints, but it also uses the product/category helpers that are
// defined in `api_helpers_and_infrastructure.go`.
func TestAPIOrderFullFlow(t *testing.T) {
	// ----------------------------------------------------------------------
	// 1️⃣  Set up a fresh in‑memory server (all repos, use‑cases and handlers)
	// ----------------------------------------------------------------------
	ts := setupTestServer(t) // returns *httptest.Server; registers cleanup automatically
	defer ts.Close()

	// ----------------------------------------------------------------------
	// 2️⃣  Create a category – needed for the product we will add later.
	// ----------------------------------------------------------------------
	catPayload := map[string]any{
		"name":        "Кофе",
		"slug":        "coffee",
		"description": "Все виды кофе",
	}
	catResp := postJSON(t, ts.URL+"/categories", catPayload)
	if catResp.Code != http.StatusCreated {
		t.Fatalf("expected 201 Created for category, got %d", catResp.Code)
	}
	var catResult struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, catResp.Body, &catResult)

	// ----------------------------------------------------------------------
	// 3️⃣  Create a product that belongs to the category we just created.
	// ----------------------------------------------------------------------
	prodPayload := map[string]any{
		"name":        "Латте",
		"description": "Молочный кофе",
		"price":       350.0,
		"category_id": catResult.ID,
		"image_url":   "https://example.com/latte.png",
		"in_stock":    true,
	}
	prodResp := postJSON(t, ts.URL+"/products", prodPayload)
	if prodResp.Code != http.StatusCreated {
		t.Fatalf("expected 201 Created for product, got %d", prodResp.Code)
	}
	var prodResult struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, prodResp.Body, &prodResult)

	// ----------------------------------------------------------------------
	// 4️⃣  Create an order that contains one item (the product above).
	// ----------------------------------------------------------------------
	orderPayload := map[string]any{
		"customer_id": "alice@example.com",
		"items": []any{
			map[string]any{
				"product_id": prodResult.ID,
				"quantity":   2,
			},
		},
	}
	orderResp := postJSON(t, ts.URL+"/orders", orderPayload)
	if orderResp.Code != http.StatusCreated {
		t.Fatalf("expected 201 Created for order, got %d", orderResp.Code)
	}
	var orderResult struct {
		ID    int64   `json:"id"`
		Total float64 `json:"total"`
		Status string `json:"status"`
	}
	decodeBody(t, orderResp.Body, &orderResult)

	// Verify that the order was created with the correct total (2 × 350 = 700)
	// and that the initial status is “new”.
	if orderResult.Total != 700.0 {
		t.Fatalf("expected total 700.0, got %v", orderResult.Total)
	}
	if orderResult.Status != "new" {
		t.Fatalf("expected status 'new', got %s", orderResult.Status)
	}

	// ----------------------------------------------------------------------
	// 5️⃣  Process the order (new → processing)
	// ----------------------------------------------------------------------
	processResp := postJSON(t, ts.URL+"/orders/"+itoa(orderResult.ID)+"/process", nil)
	if processResp.Code != http.StatusOK {
		t.Fatalf("expected 200 OK on process, got %d", processResp.Code)
	}
	var procResult struct {
		Status string `json:"status"`
	}
	decodeBody(t, processResp.Body, &procResult)
	if procResult.Status != "processing" {
		t.Fatalf("expected status 'processing' after process, got %s", procResult.Status)
	}

	// ----------------------------------------------------------------------
	// 6️⃣  Complete the order (processing → completed)
	// ----------------------------------------------------------------------
	completeResp := postJSON(t, ts.URL+"/orders/"+itoa(orderResult.ID)+"/complete", nil)
	if completeResp.Code != http.StatusOK {
		t.Fatalf("expected 200 OK on complete, got %d", completeResp.Code)
	}
	var compResult struct {
		Status string `json:"status"`
	}
	decodeBody(t, completeResp.Body, &compResult)
	if compResult.Status != "completed" {
		t.Fatalf("expected status 'completed' after complete, got %s", compResult.Status)
	}

	// ----------------------------------------------------------------------
	// 7️⃣  Final verification – GET the order and ensure the persisted status
	// ----------------------------------------------------------------------
	getResp := httptest.NewRequest(http.MethodGet, ts.URL+"/orders/"+itoa(orderResult.ID), nil)
	// reuse the helper that performs a GET and returns *httptest.ResponseRecorder
	getRec := doRequest(t, ts, getResp)
	if getRec.Code != http.StatusOK {
		t.Fatalf("expected 200 OK on final GET, got %d", getRec.Code)
	}
	var final struct {
		ID     int64   `json:"id"`
		Status string  `json:"status"`
		Total  float64 `json:"total"`
	}
	decodeBody(t, getRec.Body, &final)

	if final.Status != "completed" {
		t.Fatalf("final order status should be 'completed', got %s", final.Status)
	}
	if final.Total != 700.0 {
		t.Fatalf("final order total should still be 700.0, got %v", final.Total)
	}
}

// --------------------------------------------------------------------------
// Helper – convert int64 → string (avoids pulling strconv into every test)
// --------------------------------------------------------------------------
func itoa(i int64) string {
	return fmt.Sprintf("%d", i)
}
```

### What the test does

| Step | Action | Expected outcome |
|------|--------|------------------|
| 1️⃣ | `setupTestServer` – creates a fresh in‑memory SQLite DB, runs migrations and wires all handlers (`/categories`, `/products`, `/orders`). | Isolated environment, no test pollution. |
| 2️⃣ | `POST /categories` – creates a category. | `201 Created` and a JSON body containing the new `id`. |
| 3️⃣ | `POST /products` – creates a product that references the category created in step 2. | `201 Created` and a JSON body with the product `id`. |
| 4️⃣ | `POST /orders` – creates an order with two units of the product. | `201 Created`, `total = 2 × price (350) = 700`, `status = "new"`. |
| 5️⃣ | `POST /orders/{id}/process` – moves the order to **processing**. | `200 OK`, response JSON `status = "processing"`. |
| 6️⃣ | `POST /orders/{id}/complete` – moves the order to **completed**. | `200 OK`, response JSON `status = "completed"`. |
| 7️⃣ | `GET /orders/{id}` – fetches the persisted order. | `200 OK`, `status = "completed"` and the total is unchanged. |

### Why this test is useful

* **End‑to‑end coverage** – it walks through every layer (entity → repository → use‑case → handler) exactly once, exercising the full request/response cycle.
* **State‑machine validation** – the order status transitions (`new → processing → completed`) are verified both via the API responses and by a final GET that reads the persisted state.
* **Cross‑entity interaction** – the test proves that a product can be created only after a valid category exists, and that the order‑creation use‑case correctly looks up the product price and fills `OrderItem.Price`.
* **Isolation** – thanks to `setupTestServer(t)` each run gets a brand‑new in‑memory DB, guaranteeing deterministic results and no side‑effects between test runs.

