package entity_test

import (
	"math"
	"testing"

	"github.com/yourorg/beanbrew/internal/entity"
)

// TestUnitOrderCalculateTotalEdgeCases проверяет метод Order.CalculateTotal()
// на «крайних» (edge) ситуациях, которые пока не покрыты другими тестами
// (TestUnitOrderCalculateTotal*, TestUnitOrderCalculateTotalFloatPrecision и т.п.).
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	// Таблица тест‑кейсов.  Каждый кейс описывает набор OrderItem‑ов,
	// ожидаемое значение Total и (необязательно) комментарий о том,
	// почему данный кейс считается «крайним».
	tests := []struct {
		name        string
		items       []entity.OrderItem
		wantTotal   float64
		wantIsNaN   bool // если true – ожидаем NaN в результате
		wantIsInf   bool // если true – ожидаем +Inf в результате
		precision   float64
	}{
		{
			name: "zero_price_items",
			// Цена 0, но количество >0 – итоговая сумма должна быть 0.
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 5, Price: 0},
				{ProductID: 2, Quantity: 3, Price: 0},
			},
			wantTotal: 0,
			precision: 0,
		},
		{
			name: "zero_quantity_items",
			// Количество 0, но цена >0 – тоже 0, т.к. 0*price = 0.
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 0, Price: 100},
				{ProductID: 2, Quantity: 0, Price: 250},
			},
			wantTotal: 0,
			precision: 0,
		},
		{
			name: "negative_price",
			// В реальном коде валидация не допускает отрицательную цену,
			// но метод CalculateTotal должен корректно её обработать.
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 2, Price: -50},
				{ProductID: 2, Quantity: 1, Price: 200},
			},
			// (-50)*2 + 200*1 = 100
			wantTotal: 100,
			precision: 0,
		},
		{
			name: "overflow_to_inf",
			// Очень большие значения, которые в результате дают +Inf.
			// 1e308 * 10 = 1e309 → +Inf (float64 overflow).
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 10, Price: 1e308},
			},
			wantIsInf: true,
		},
		{
			name: "nan_price_propagates",
			// Если один из элементов имеет NaN‑цену, итоговая сумма тоже NaN.
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 1, Price: 100},
				{ProductID: 2, Quantity: 1, Price: math.NaN()},
			},
			wantIsNaN: true,
		},
		{
			name: "nil_items_slice",
			// nil‑slice должна вести себя так же, как пустой срез.
			items:     nil,
			wantTotal: 0,
			precision: 0,
		},
		{
			name: "mixed_edge_cases",
			// Сочетание разных «крайних» значений в одном заказе.
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 0, Price: 0},          // 0
				{ProductID: 2, Quantity: 3, Price: -10},       // -30
				{ProductID: 3, Quantity: 2, Price: 1e308},      // 2e308 → +Inf
				{ProductID: 4, Quantity: 1, Price: math.NaN()}, // NaN
			},
			// При наличии NaN результат всегда NaN (по правилам IEEE‑754).
			wantIsNaN: true,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			// Подготовка заказа
			o := &entity.Order{
				Items: tt.items,
			}

			// Выполняем расчёт
			o.CalculateTotal()

			// Проверяем, что поле Total заполнено ожидаемым значением.
			if tt.wantIsNaN {
				if !math.IsNaN(o.Total) {
					t.Fatalf("expected Total to be NaN, got %v", o.Total)
				}
				return
			}
			if tt.wantIsInf {
				if !math.IsInf(o.Total, +1) {
					t.Fatalf("expected Total to be +Inf, got %v", o.Total)
				}
				return
			}
			// Для обычных чисел сравниваем с точностью, если указана.
			if tt.precision == 0 {
				if o.Total != tt.wantTotal {
					t.Fatalf("expected Total %v, got %v", tt.wantTotal, o.Total)
				}
			} else {
				if diff := math.Abs(o.Total - tt.wantTotal); diff > tt.precision {
					t.Fatalf("Total differs more than %.10f: want %v, got %v (diff %.10f)",
						tt.precision, tt.wantTotal, o.Total, diff)
				}
			}
		})
	}
}
```

