#### 3. Установить PRAGMA‑ы, которые делают `LIKE` нечувствительным к регистру и Unicode‑aware
```go
func setupTestDB(t *testing.T) *sql.DB {
    db, err := sql.Open("sqlite3", ":memory:")
    if err != nil { t.Fatalf(...) }
    // Эти pragma‑ы работают только если SQLite собран с ICU.
    db.Exec(`PRAGMA case_sensitive_like = OFF;`)
    db.Exec(`PRAGMA foreign_keys = ON;`)
    // При необходимости включаем колляцию:
    db.Exec(`PRAGMA encoding = "UTF-8";`)
    // …
    return db
}
```

