func TestIntegrationProductSearch(t *testing.T) {
    // …создаём 3 продукта…
    got, err := repo.Search("молок", 0)
    if err != nil { t.Fatalf(...) }

    // Сортируем полученный срез по ID (или Name) – гарантируем детерминированность.
    sort.Slice(got, func(i, j int) bool { return got[i].ID < got[j].ID })

    if want := 2; len(got) != want {
        t.Fatalf("expected %d results, got %d", want, len(got))
    }
    // При необходимости проверяем конкретные ID/Name, но без привязки к индексу.
}
```
* Можно также сравнивать множества: собрать `map[int64]bool` из `got` и убедиться, что в нём присутствуют нужные ID.

#### 5. Добавить отдельный тест‑утилиту, проверяющую поддержку Unicode‑LIKE
```go
func TestSQLiteUnicodeLike(t *testing.T) {
    db := setupTestDB(t)
    db.Exec(`CREATE TABLE t (txt TEXT);`)
    db.Exec(`INSERT INTO t (txt) VALUES ('молоко');`)

    var cnt int
    db.QueryRow(`SELECT COUNT(*) FROM t WHERE lower(txt) LIKE lower(?)`, "%молок%").
        Scan(&cnt)
    if cnt != 1 {
        t.Fatalf("Unicode LIKE не работает, cnt=%d", cnt)
    }
}
```
* Если такой тест падает, значит драйвер/SQLite не поддерживает Unicode‑LIKE и нужно переключить драйвер или собрать с ICU.

