### 2. Переиспользовать одну БД для всех **интеграционных** тестов репозитория

*Текущий подход* – `setupTestDB` в каждом `*_test.go`.  
*Оптимизированный подход* – один `TestMain` открывает `:memory:`‑БД, запускает миграции, а каждый тест получает **транзакцию**, которую откатываем в `t.Cleanup`.

```go
// repository/integration_test.go
var (
    db  *sql.DB
    mu  sync.Mutex // защита от race, если тесты запущены параллельно
)

func TestMain(m *testing.M) {
    var err error
    db, err = sql.Open("sqlite3", ":memory:")
    if err != nil {
        log.Fatalf("open db: %v", err)
    }
    if err = migrations.Run(db); err != nil {
        log.Fatalf("run migrations: %v", err)
    }
    code := m.Run()
    db.Close()
    os.Exit(code)
}

// helper – возвращает *sql.Tx, откатывается в Cleanup
func withTx(t *testing.T) *sql.Tx {
    t.Helper()
    tx, err := db.Begin()
    if err != nil {
        t.Fatalf("begin tx: %v", err)
    }
    t.Cleanup(func() {
        tx.Rollback()
    })
    return tx
}
```

Тогда в тесте:

