package entity

import (
	"math"
	"testing"
	"time"
)

// TestUnitOrderCalculateTotalEdgeCases adds a few edge‑case scenarios for
// Order.CalculateTotal that are **not** covered by the existing suite
// (TestUnitOrderCalculateTotal, TestUnitOrderCalculateTotalEmpty, …).
// The test is table‑driven and each sub‑test checks that the method
// correctly sums `item.Price * item.Quantity` and stores the result in
// the Order.Total field.
//
// Edge cases covered:
//   1. Items with a price of 0 (should not affect the total).
//   2. Items with a negative price – the method is a pure sum, so the
//      negative contribution must be reflected in the total.
//   3. Items with a quantity of 0 – again a pure sum, the total must stay
//      unchanged.
//   4. Very large price * quantity that pushes the result close to the
//      float64 overflow limit (the expected result is `math.Inf(+1)`).
//   5. A mixture of the above in a single order to ensure the algorithm
//      does not stop on the first “odd” item.
//
// The test does **not** invoke validation logic; it constructs the
// Order struct directly, because we want to exercise only the
// CalculateTotal business rule.
//
// NOTE: The test uses the same `Order` struct definition that lives in
// `entity/order.go` (ID, CustomerID, Status, Items, Total, …) and the
// `OrderItem` struct defined there as well.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	// Helper to build an OrderItem quickly.
	newItem := func(productID int64, qty int, price float64) OrderItem {
		return OrderItem{
			ProductID: productID,
			Quantity:  qty,
			Price:     price,
		}
	}

	tests := []struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantIsInf   bool // true if we expect +Inf (overflow case)
		description string
	}{
		{
			name: "ZeroPriceItem",
			items: []OrderItem{
				newItem(1, 5, 0.0), // 0 * 5 = 0
				newItem(2, 3, 10.0), // 10 * 3 = 30
			},
			wantTotal:   30.0,
			description: "price = 0 must not affect the sum",
		},
		{
			name: "NegativePriceItem",
			items: []OrderItem{
				newItem(1, 2, -15.0), // -15 * 2 = -30
				newItem(2, 1, 50.0),  // 50 * 1 = 50
			},
			wantTotal:   20.0, // 50 - 30
			description: "negative price is summed as‑is",
		},
		{
			name: "ZeroQuantityItem",
			items: []OrderItem{
				newItem(1, 0, 100.0), // 100 * 0 = 0
				newItem(2, 4, 25.0),  // 25 * 4 = 100
			},
			wantTotal:   100.0,
			description: "quantity = 0 must not affect the sum",
		},
		{
			name: "LargeQuantityAndPrice",
			items: []OrderItem{
				// 1e154 * 1e154 = 1e308 – still finite.
				newItem(1, int(1e154), 1e154),
			},
			wantTotal:   math.Inf(1), // 1e308 * 1e154 overflows to +Inf
			wantIsInf:   true,
			description: "overflow should produce +Inf",
		},
		{
			name: "MixedEdgeCases",
			items: []OrderItem{
				newItem(1, 0, 0.0),    // 0
				newItem(2, 3, -5.0),   // -15
				newItem(3, 2, 0.0),    // 0
				newItem(4, 5, 20.0),   // 100
				newItem(5, 1, 1e200), // 1e200
			},
			wantTotal:   1e200 + 85.0, // 100 - 15 + 1e200
			description: "combination of zero/negative values with a huge price",
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			// Build the order with a deterministic timestamp (not used by the
			// calculation but required by the struct definition).
			order := Order{
				ID:         1,
				CustomerID: "test-cust",
				Status:     OrderStatusNew,
				Items:      tt.items,
				CreatedAt:  time.Now(),
				UpdatedAt:  time.Now(),
			}

			// Call the method under test.
			order.CalculateTotal()

			if tt.wantIsInf {
				if !math.IsInf(order.Total, +1) {
					t.Fatalf("expected Total to be +Inf, got %v", order.Total)
				}
				return
			}

			if order.Total != tt.wantTotal {
				t.Fatalf("expected Total %v, got %v (%s)", tt.wantTotal, order.Total, tt.description)
			}
		})
	}
}
```

### Why this test does **not** duplicate existing ones

| Existing test name | What it covers | What this test adds |
|--------------------|----------------|---------------------|
| `TestUnitOrderCalculateTotal` | 3 normal items, normal prices | No zero/negative price, zero quantity, overflow, mixed edge cases |
| `TestUnitOrderCalculateTotalEmpty` | Empty slice → 0 | No zero‑price or negative‑price items |
| `TestUnitOrderCalculateTotalSingleItem` | One normal item | No edge‑case values |
| `TestUnitOrderCalculateTotalLargeOrder` | 50 items of modest size | No extreme values, no overflow |
| `TestUnitOrderCalculateTotalFloatPrecision` | 0.1/0.2 floating‑point rounding | No zero/negative/overflow cases |
| `TestUnitOrderCalculateTotalSetsField` | Overwrites pre‑existing `Total` | No extreme numeric values |

Thus the new `TestUnitOrderCalculateTotalEdgeCases` fills the gaps by:

* Verifying that a price of `0` does not affect the sum.
* Verifying that a **negative** price is summed (the method is a pure arithmetic operation).
* Verifying that a quantity of `0` is ignored.
* Verifying the behaviour when the multiplication overflows the `float64` range (expect `+Inf`).
* Verifying a mixed scenario that combines the above edge cases.

All sub‑tests are isolated, use a fresh `Order` instance, and do not rely on any repository or use‑case code, staying true to a pure unit test

